public class BitOps {
    // Check if bit k is set
    static boolean isBitSet(int n, int k) { return ((n >> k) & 1) == 1; }
    // Set bit k
    static int setBit(int n, int k) { return n | (1 << k); }
    // Clear bit k
    static int clearBit(int n, int k) { return n & ~(1 << k); }
    // Toggle bit k
    static int toggleBit(int n, int k) { return n ^ (1 << k); }
    // Count set bits — Brian Kernighan's algorithm
    static int countBits(int n) {
        int count = 0;
        while (n != 0) { n &= n - 1; count++; } // clears lowest set bit each iter
        return count;
    }
    // Is power of two?
    static boolean isPowerOfTwo(int n) { return n > 0 && (n & (n-1)) == 0; }
    // Get lowest set bit position
    static int lowestSetBit(int n) { return n & (-n); }

    public static void main(String[] args) {
        int n = 0b1010; // 10 in binary
        System.out.println("n = " + n + " = " + Integer.toBinaryString(n));
        System.out.println("Bit 1 set? " + isBitSet(n, 1));  // bit 1 = 1 → true
        System.out.println("Bit 2 set? " + isBitSet(n, 2));  // bit 2 = 0 → false
        System.out.println("Set bit 0: " + Integer.toBinaryString(setBit(n, 0)));   // 1011
        System.out.println("Clear bit 1: " + Integer.toBinaryString(clearBit(n, 1)));// 1000
        System.out.println("Toggle bit 0: " + Integer.toBinaryString(toggleBit(n,0)));// 1011
        System.out.println("Count bits in 7: " + countBits(7));   // 3 (111)
        System.out.println("Count bits in 12: " + countBits(12)); // 2 (1100)
        System.out.println("16 power of 2? " + isPowerOfTwo(16)); // true
        System.out.println("12 power of 2? " + isPowerOfTwo(12)); // false
        System.out.println("Lowest bit of 12: " + lowestSetBit(12)); // 4 (100)
        // Same as Integer.bitCount(n)
        System.out.println("Java built-in: " + Integer.bitCount(255)); // 8
    }
}

import java.util.*;

public class XorAndBitmask {

    // ── XOR: Find single unique element among pairs ──────────────
    static int singleNumber(int[] nums) {
        int result = 0;
        for (int n : nums) result ^= n; // pairs cancel: a^a=0
        return result; // only unique survives
    }

    // ── XOR: Find two non-duplicate numbers (harder variant) ─────
    static int[] twoSingleNumbers(int[] nums) {
        int xorAll = 0;
        for (int n : nums) xorAll ^= n; // xorAll = a ^ b
        // Find any differing bit between a and b
        int diffBit = xorAll & (-xorAll); // lowest set bit
        int a = 0;
        for (int n : nums)
            if ((n & diffBit) != 0) a ^= n; // group by that bit
        return new int[]{a, xorAll ^ a}; // b = xorAll ^ a
    }

    // ── Bitmask: Enumerate all subsets of a set ───────────────────
    static void enumerateSubsets(int[] set) {
        int n = set.length;
        // 1<<n = 2^n possible subsets
        for (int mask = 0; mask < (1 << n); mask++) {
            List<Integer> subset = new ArrayList<>();
            for (int i = 0; i < n; i++)
                if ((mask & (1 << i)) != 0) // bit i is set in mask
                    subset.add(set[i]);
            System.out.println(Integer.toBinaryString(mask) + " → " + subset);
        }
    }

    // ── Bitmask: Subset sum with tracking ────────────────────────
    static boolean subsetSumExists(int[] arr, int target) {
        int n = arr.length;
        for (int mask = 0; mask < (1 << n); mask++) {
            int sum = 0;
            for (int i = 0; i < n; i++)
                if ((mask >> i & 1) == 1) sum += arr[i];
            if (sum == target) return true;
        }
        return false;
    }

    public static void main(String[] args) {
        System.out.println(singleNumber(new int[]{4,1,2,1,2}));    // 4
        System.out.println(Arrays.toString(twoSingleNumbers(new int[]{1,2,1,3,2,5}))); // [3,5]
        System.out.println();
        System.out.println("Subsets of {1,2,3}:");
        enumerateSubsets(new int[]{1, 2, 3});
        System.out.println("\nSubset sum 6 in {1,3,5,2}: " + subsetSumExists(new int[]{1,3,5,2}, 6));
    }
}

